/// <summary>
/// Class entry point. The system will call this method when a designated menu 
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
        CustInvoiceTable        custInvoiceTable;
        SrsReportRunController  reportRunController;
        SrsReportRunImpl        srsReportRun;
        FreeTextInvoiceContract dataContract;
        CustInvoiceJour         custInvoiceJour;

        if(_args.record() && _args.dataset() == tableNum(CustInvoiceTable))
        {
            custInvoiceTable = _args.record();
        }
        else
        {
            throw Error(Error::missingFormActiveBuffer(formStr(CustFreeInvoice)));
        }

        reportRunController = new SrsReportRunController();
        dataContract        = new FreeTextInvoiceContract();
        reportRunController.parmReportName(ssrsReportStr(ETGFreeTextInvoice, ETGReportPL));
        reportRunController.parmShowDialog(false);
        dataContract = reportRunController.parmReportContract().parmRdpContract() as FreeTextInvoiceContract;

        select firstonly RecId from CustInvoiceJour where custInvoiceJour.InvoiceId == custInvoiceTable.InvoiceId;

        dataContract.parmCustInvoiceJourRecId(custInvoiceJour.RecId);
        srsReportRun = reportRunController.parmReportRun() as SrsReportRunImpl;
        reportRunController.parmShowDialog(false);
        reportRunController.parmReportRun(srsReportRun);
        reportRunController.parmReportContract().parmPrintSettings().printMediumType(SRSPrintMediumType::Screen);
        reportRunController.startOperation();
}
